            if (target_pitch_angle > PITCH_ANGLE_MAX) target_pitch_angle = PITCH_ANGLE_MAX;
            if (target_pitch_angle < PITCH_ANGLE_MIN) target_pitch_angle = PITCH_ANGLE_MIN;
        } else {
            // 使用遥控器数据进行手动控制
            int16_t rc_yaw_raw = remote_ctrl.rc.ch[0];
