typedef enum {
    CAN1_YAW_MOTOR_ID   = 0x100,    // YAW轴电机扩展帧ID
    CAN1_PITCH_MOTOR_ID = 0x200     // PITCH轴电机扩展帧ID
} StepperMotorID_e;

